import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

const BookingConfirmation = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const listing = location.state?.listing;

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      <div className="flex flex-col items-center justify-center py-20 text-center">
        <h1 className="text-4xl font-bold text-pink-600 mb-4">
          Booking Confirmed 🎉
        </h1>
        <p className="text-gray-700 mb-6">
          Your reservation has been successfully confirmed!
        </p>

        {listing && (
          <div className="bg-white shadow-md rounded-2xl p-6 w-96 text-left">
            <img
              src={listing.image}
              alt={listing.title}
              className="rounded-lg mb-4 h-48 w-full object-cover"
            />
            <h3 className="text-xl font-semibold">{listing.title}</h3>
            <p className="text-gray-500">{listing.location}</p>
            <p className="text-pink-600 font-bold mt-2">{listing.price}</p>
          </div>
        )}

        <button
          className="mt-8 bg-pink-500 hover:bg-pink-600 text-white px-6 py-3 rounded-full shadow-lg transition-all"
          onClick={() => navigate("/")}
        >
          Go to Home 🏠
        </button>
      </div>
    </div>
  );
};

export default BookingConfirmation;
